func createAutoEmbeddingIndex(ctx context.Context, coll *mongo.Collection) error {
        // Define the index fields.
        definition := autoEmbedIndexDefinition{
                Fields: []any{
                        autoEmbedField{
                                Type:     "autoEmbed",
                                Modality: "text",
                                Path:     "fullplot",
                                Model:    "voyage-4",
                        },
                },
        }

        // Set index name and type "vectorSearch".
        opts := options.SearchIndexes().
